import{_ as e,o as r,c as i,ag as t}from"./chunks/framework.Culc7SYV.js";const p=JSON.parse('{"title":"Cards","description":"","frontmatter":{},"headers":[],"relativePath":"Cards.md","filePath":"Cards.md","lastUpdated":1773806339000}'),l={name:"Cards.md"};function s(o,a,d,n,c,h){return r(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="cards" tabindex="-1">Cards <a class="header-anchor" href="#cards" aria-label="Permalink to &quot;Cards&quot;">​</a></h1><p>Last modified: 17/03/2026</p><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>Cards are the core study unit in LearnKit. You can create them in your notes, format them for clear recall, and manage them across browser and review flows.</p><h2 id="card-types" tabindex="-1">Card types <a class="header-anchor" href="#card-types" aria-label="Permalink to &quot;Card types&quot;">​</a></h2><ul><li><a href="./Basic-&amp;-Reversed-Cards">Basic &amp; Reversed Cards</a>: direct question/answer recall</li><li><a href="./Cloze-Cards">Cloze Cards</a>: fill-in-the-blank recall in context</li><li><a href="./Image-Occlusion">Image Occlusion</a>: hide parts of images</li><li><a href="./Multiple-Choice-Questions">Multiple Choice Questions</a>: choose the correct option</li><li><a href="./Ordered-Questions">Ordered Questions</a>: remember sequences</li></ul><h2 id="build-flow" tabindex="-1">Build Flow <a class="header-anchor" href="#build-flow" aria-label="Permalink to &quot;Build Flow&quot;">​</a></h2><p>Two reliable approaches:</p><ol><li>Write card syntax directly in notes.</li><li>Use Add flashcard actions from the context menu or command palette.</li></ol><p>See <a href="./Creating-Cards">Creating Cards</a>, <a href="./Reading-View">Reading View</a>, <a href="./Reading-View-Styles">Reading View Styles</a>, and <a href="./Custom-Reading-Styles">Custom Reading Styles</a>.</p><h2 id="edit-flow" tabindex="-1">Edit Flow <a class="header-anchor" href="#edit-flow" aria-label="Permalink to &quot;Edit Flow&quot;">​</a></h2><p>You can edit cards:</p><ul><li>in the source note</li><li>in <a href="./Card-Browser">Card Browser</a></li><li>during review (edit action)</li></ul><p>See <a href="./Editing-Cards">Editing Cards</a>.</p><h2 id="organize-cards" tabindex="-1">Organize Cards <a class="header-anchor" href="#organize-cards" aria-label="Permalink to &quot;Organize Cards&quot;">​</a></h2><ul><li>Use groups to organize cards.</li><li>Use <a href="./Card-Formatting">Card Formatting</a> for markdown, math, links, and images.</li><li>Use <a href="./Flags">Flags</a> for inline circle-flag tokens.</li></ul><h2 id="key-notes" tabindex="-1">Key Notes <a class="header-anchor" href="#key-notes" aria-label="Permalink to &quot;Key Notes&quot;">​</a></h2><ul><li>Broken or incomplete card syntax can cause cards to be skipped or parsed incorrectly.</li><li>Card scheduling data is separate from note text (see <a href="./Backups">Backups</a>).</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./Flashcards">Flashcards</a></li><li><a href="./Study-Sessions">Study Sessions</a></li><li><a href="./Syncing">Syncing</a></li></ul>',20)])])}const f=e(l,[["render",s]]);export{p as __pageData,f as default};
